import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Dashboard.css';

const API_BASE = 'https://nordcomply-api.dshvan5.workers.dev';

export default function Dashboard() {
  const navigate = useNavigate();
  const [tenants, setTenants] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchTenants();
  }, []);

  async function fetchTenants() {
    try {
      setLoading(true);
      const res = await fetch(`${API_BASE}/api/tenants`);
      if (!res.ok) throw new Error('Failed to fetch');
      const data = await res.json();
      setTenants(data);
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="dashboard">
      <div className="dashboard__header">
        <h1>Dashboard</h1>
        <p>Oversigt over dine M365 tenants</p>
      </div>

      <div className="dashboard__stats">
        <div className="stat-card">
          <div className="stat-label">TOTAL TENANTS</div>
          <div className="stat-value">{tenants.length}</div>
        </div>

        <div className="stat-card">
          <div className="stat-label">AKTIVE</div>
          <div className="stat-value">✓ {tenants.length}</div>
        </div>

        <div className="stat-card">
          <div className="stat-label">STATUS</div>
          <div className="stat-value">{tenants.length > 0 ? 'Healthy' : 'No data'}</div>
        </div>
      </div>

      <div className="dashboard__section">
        <div className="dashboard__section-header">
          <h2>Recent Activity</h2>
          <button onClick={() => navigate('/tenants')} className="btn-secondary">
            Manage Tenants →
          </button>
        </div>

        {loading ? (
          <p className="loading">Indlæser...</p>
        ) : tenants.length === 0 ? (
          <div className="empty-state">
            <p>Du har ingen tenants endnu</p>
            <button onClick={() => navigate('/admin')} className="btn-primary">
              Tilføj første tenant
            </button>
          </div>
        ) : (
          <div className="activity-list">
            {tenants.map((tenant) => (
              <div key={tenant.id} className="activity-item">
                <div className="activity-icon">📊</div>
                <div className="activity-content">
                  <h4>{tenant.name}</h4>
                  <p>Tilføjet {new Date(tenant.addedAt).toLocaleDateString('da-DK')}</p>
                </div>
                <div className="activity-status">✓ Aktiv</div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
